// License compliance checker: classifies dependencies against
// allow/deny lists and builds a compliance report.

import type {
  ComplianceEntry,
  ComplianceReport,
  ComplianceStatus,
  Dependency,
  LicenseConfig,
  LicenseLookupFn,
} from "./types";

/** Classify a single license string against the config lists.
 *  Matching is case-insensitive. Returns 'unknown' if license is null
 *  or not found in either list. */
export function classifyLicense(
  license: string | null,
  config: LicenseConfig
): ComplianceStatus {
  if (license === null) return "unknown";

  const lower = license.toLowerCase();

  if (config.allowList.some((l) => l.toLowerCase() === lower)) {
    return "approved";
  }
  if (config.denyList.some((l) => l.toLowerCase() === lower)) {
    return "denied";
  }

  return "unknown";
}

/** Check all dependencies against the license config.
 *  Uses the provided lookup function to resolve licenses (allows mocking). */
export async function checkCompliance(
  deps: Dependency[],
  config: LicenseConfig,
  lookupFn: LicenseLookupFn
): Promise<ComplianceReport> {
  const entries: ComplianceEntry[] = [];
  let approved = 0;
  let denied = 0;
  let unknown = 0;

  for (const dep of deps) {
    const info = await lookupFn(dep.name, dep.version);
    const status = classifyLicense(info.license, config);

    entries.push({
      name: dep.name,
      version: dep.version,
      license: info.license,
      status,
    });

    if (status === "approved") approved++;
    else if (status === "denied") denied++;
    else unknown++;
  }

  return {
    entries,
    summary: {
      total: deps.length,
      approved,
      denied,
      unknown,
    },
  };
}

// Mock license lookup: simulates querying an external registry for license info.
// In production, this would call npm registry API or PyPI API.

import type { LicenseInfo, LicenseLookupFn } from "./types";

/** Well-known package licenses used by the mock lookup */
const MOCK_LICENSE_DB: Record<string, string> = {
  // npm packages
  express: "MIT",
  lodash: "MIT",
  react: "MIT",
  "react-dom": "MIT",
  typescript: "Apache-2.0",
  axios: "MIT",
  webpack: "MIT",
  jest: "MIT",
  chalk: "MIT",
  "left-pad": "WTFPL",
  "gpl-crypto": "GPL-3.0",
  "agpl-server": "AGPL-3.0",
  // Python packages
  requests: "Apache-2.0",
  flask: "BSD-3-Clause",
  django: "BSD-3-Clause",
  numpy: "BSD-3-Clause",
  pandas: "BSD-3-Clause",
  "gpl-tool": "GPL-3.0",
};

/** Mock license lookup function.
 *  Returns the license from MOCK_LICENSE_DB or null if not found. */
export const mockLicenseLookup: LicenseLookupFn = async (
  name: string,
  version: string
): Promise<LicenseInfo> => {
  const license = MOCK_LICENSE_DB[name] ?? null;
  return { name, version, license };
};

/** Create a custom mock lookup from a mapping */
export function createMockLookup(
  mapping: Record<string, string>
): LicenseLookupFn {
  return async (name: string, version: string): Promise<LicenseInfo> => {
    const license = mapping[name] ?? null;
    return { name, version, license };
  };
}

