// Workflow structure tests: validate the GitHub Actions workflow YAML,
// verify file references, and run actionlint.
// These tests also run the full pipeline through act and assert on output.

import { describe, test, expect, beforeAll } from "bun:test";
import * as yaml from "js-yaml";
import { existsSync } from "fs";
import { resolve, dirname } from "path";
import { spawnSync } from "child_process";

const PROJECT_ROOT = resolve(dirname(import.meta.dir));
const WORKFLOW_PATH = resolve(
  PROJECT_ROOT,
  ".github/workflows/dependency-license-checker.yml"
);
const ACT_RESULT_PATH = resolve(PROJECT_ROOT, "act-result.txt");

// -- Helper: read and parse the workflow YAML --
function loadWorkflow(): Record<string, unknown> {
  const content = Bun.file(WORKFLOW_PATH);
  // Synchronous read via readFileSync since yaml.load needs a string
  const text = require("fs").readFileSync(WORKFLOW_PATH, "utf-8");
  return yaml.load(text) as Record<string, unknown>;
}

// ============================================================
// 1. Workflow Structure Tests
// ============================================================
describe("Workflow structure", () => {
  let workflow: Record<string, unknown>;

  beforeAll(() => {
    workflow = loadWorkflow();
  });

  test("workflow file exists", () => {
    expect(existsSync(WORKFLOW_PATH)).toBe(true);
  });

  test("has correct trigger events", () => {
    const on = workflow["on"] as Record<string, unknown>;
    expect(on).toBeDefined();
    expect("push" in on).toBe(true);
    expect("pull_request" in on).toBe(true);
    expect("workflow_dispatch" in on).toBe(true);
  });

  test("has license-check job", () => {
    const jobs = workflow["jobs"] as Record<string, unknown>;
    expect(jobs).toBeDefined();
    expect("license-check" in jobs).toBe(true);
  });

  test("job has correct steps", () => {
    const jobs = workflow["jobs"] as Record<string, Record<string, unknown>>;
    const job = jobs["license-check"];
    const steps = job["steps"] as Array<Record<string, unknown>>;

    // Should have checkout, setup-bun, install, test, and fixture check steps
    expect(steps.length).toBeGreaterThanOrEqual(6);

    // First step: checkout
    expect(steps[0]["uses"]).toBe("actions/checkout@v4");

    // Second step: setup-bun
    expect(steps[1]["uses"]).toBe("oven-sh/setup-bun@v2");
  });

  test("references existing script files", () => {
    // Check that files referenced in the workflow exist
    const scriptFiles = [
      "src/main.ts",
      "fixtures/all-approved-package.json",
      "fixtures/has-denied-package.json",
      "fixtures/mixed-requirements.txt",
      "fixtures/license-config.json",
    ];

    for (const file of scriptFiles) {
      const fullPath = resolve(PROJECT_ROOT, file);
      expect(existsSync(fullPath)).toBe(true);
    }
  });

  test("permissions are set", () => {
    const permissions = workflow["permissions"] as Record<string, unknown>;
    expect(permissions).toBeDefined();
    expect(permissions["contents"]).toBe("read");
  });
});

// ============================================================
// 2. Actionlint Validation
// ============================================================
describe("Actionlint validation", () => {
  test("actionlint passes with no errors", () => {
    const result = spawnSync("actionlint", [WORKFLOW_PATH], {
      encoding: "utf-8",
    });
    expect(result.status).toBe(0);
  });
});

// ============================================================
// 3. Act Integration Tests
// ============================================================
describe("Act integration", () => {
  let actOutput: string;
  let actExitCode: number;

  beforeAll(() => {
    // Run act in a temporary git repo with all project files
    // This is a single act run that exercises all test cases via the workflow
    const tmpDir = spawnSync("mktemp", ["-d"], { encoding: "utf-8" }).stdout.trim();

    // Copy project files into temp dir
    spawnSync("cp", ["-r", ".", tmpDir + "/project"], {
      cwd: PROJECT_ROOT,
      encoding: "utf-8",
    });

    // Initialize a git repo (act requires it)
    spawnSync("git", ["init"], { cwd: tmpDir + "/project", encoding: "utf-8" });
    spawnSync("git", ["add", "-A"], { cwd: tmpDir + "/project", encoding: "utf-8" });
    spawnSync("git", ["config", "user.email", "test@test.com"], {
      cwd: tmpDir + "/project",
      encoding: "utf-8",
    });
    spawnSync("git", ["config", "user.name", "test"], {
      cwd: tmpDir + "/project",
      encoding: "utf-8",
    });
    spawnSync("git", ["commit", "-m", "test"], {
      cwd: tmpDir + "/project",
      encoding: "utf-8",
    });

    // Run act
    const actResult = spawnSync(
      "act",
      ["push", "--rm"],
      {
        cwd: tmpDir + "/project",
        encoding: "utf-8",
        timeout: 300000, // 5 minutes
        env: { ...process.env, DOCKER_HOST: process.env.DOCKER_HOST },
      }
    );

    actOutput = (actResult.stdout || "") + "\n" + (actResult.stderr || "");
    actExitCode = actResult.status ?? 1;

    // Write act output to act-result.txt
    const header = "=== ACT RUN: Full pipeline (all fixtures) ===\n";
    const delimiter = "\n" + "=".repeat(60) + "\n";
    require("fs").writeFileSync(
      ACT_RESULT_PATH,
      header + actOutput + delimiter,
      "utf-8"
    );

    // Cleanup temp dir
    spawnSync("rm", ["-rf", tmpDir]);
  }, 360000); // 6 minute timeout for beforeAll

  test("act exits with code 0", () => {
    expect(actExitCode).toBe(0);
  });

  test("act-result.txt exists", () => {
    expect(existsSync(ACT_RESULT_PATH)).toBe(true);
  });

  test("job succeeded", () => {
    expect(actOutput).toContain("Job succeeded");
  });

  // -- Unit test assertions --
  test("unit tests ran and passed", () => {
    // Bun test output shows pass count
    expect(actOutput).toMatch(/\d+ pass/);
    expect(actOutput).toContain("0 fail");
  });

  // -- All-approved fixture assertions --
  test("all-approved fixture: found 4 dependencies", () => {
    expect(actOutput).toContain("Found 4 dependencies");
  });

  test("all-approved fixture: all approved", () => {
    expect(actOutput).toContain("Approved: 4");
    expect(actOutput).toContain("Denied: 0");
    expect(actOutput).toContain("Unknown: 0");
  });

  test("all-approved fixture: PASS message", () => {
    expect(actOutput).toContain("PASS: All dependencies have acceptable licenses.");
  });

  test("all-approved fixture: exit marker", () => {
    expect(actOutput).toContain("ALL_APPROVED_EXIT=0");
  });

  // -- Has-denied fixture assertions --
  test("has-denied fixture: found 2 dependencies", () => {
    expect(actOutput).toContain("Found 2 dependencies");
  });

  test("has-denied fixture: detected denied license", () => {
