// Workflow structure tests: validate YAML, structure, and script references
// These tests parse the workflow file and verify its correctness without running act.

import { describe, test, expect } from "bun:test";
import * as yaml from "js-yaml";
import { existsSync } from "fs";

const WORKFLOW_PATH = ".github/workflows/dependency-license-checker.yml";

const workflowContent = await Bun.file(WORKFLOW_PATH).text();
const workflow = yaml.load(workflowContent) as Record<string, any>;

describe("Workflow structure", () => {
  test("workflow file exists", () => {
    expect(existsSync(WORKFLOW_PATH)).toBe(true);
  });

  test("has correct trigger events", () => {
    expect(workflow.on).toBeDefined();
    expect(workflow.on.push).toBeDefined();
    expect(workflow.on.pull_request).toBeDefined();
    expect(workflow.on.workflow_dispatch).toBeDefined();
  });

  test("has permissions set", () => {
    expect(workflow.permissions).toBeDefined();
    expect(workflow.permissions.contents).toBe("read");
  });

  test("has license-check job", () => {
    expect(workflow.jobs["license-check"]).toBeDefined();
  });

  test("license-check job uses ubuntu-latest", () => {
    expect(workflow.jobs["license-check"]["runs-on"]).toBe("ubuntu-latest");
  });

  test("first step is checkout", () => {
    const steps = workflow.jobs["license-check"].steps;
    expect(steps[0].uses).toBe("actions/checkout@v4");
  });

  test("has bun setup step", () => {
    const steps = workflow.jobs["license-check"].steps;
    const bunStep = steps.find((s: any) => s.uses && s.uses.startsWith("oven-sh/setup-bun@"));
    expect(bunStep).toBeDefined();
  });

  test("has install dependencies step", () => {
    const steps = workflow.jobs["license-check"].steps;
    const installStep = steps.find((s: any) => s.run && s.run.includes("bun install"));
    expect(installStep).toBeDefined();
  });

  test("has unit test step", () => {
    const steps = workflow.jobs["license-check"].steps;
    const testStep = steps.find((s: any) => s.run && s.run.includes("bun test"));
    expect(testStep).toBeDefined();
  });

  test("has all-approved fixture check step", () => {
    const steps = workflow.jobs["license-check"].steps;
    const step = steps.find((s: any) => s.run && s.run.includes("all-approved-package.json"));
    expect(step).toBeDefined();
  });

  test("has denied fixture check step", () => {
    const steps = workflow.jobs["license-check"].steps;
    const step = steps.find((s: any) => s.run && s.run.includes("has-denied-package.json"));
    expect(step).toBeDefined();
  });

  test("has requirements.txt fixture check step", () => {
    const steps = workflow.jobs["license-check"].steps;
    const step = steps.find((s: any) => s.run && s.run.includes("mixed-requirements.txt"));
    expect(step).toBeDefined();
  });
});

describe("Script file references", () => {
  test("src/main.ts exists", () => {
    expect(existsSync("src/main.ts")).toBe(true);
  });

  test("src/parser.ts exists", () => {
    expect(existsSync("src/parser.ts")).toBe(true);
  });

  test("src/checker.ts exists", () => {
    expect(existsSync("src/checker.ts")).toBe(true);
  });

  test("src/report.ts exists", () => {
    expect(existsSync("src/report.ts")).toBe(true);
  });

  test("src/types.ts exists", () => {
    expect(existsSync("src/types.ts")).toBe(true);
  });

  test("fixture files referenced in workflow exist", () => {
    expect(existsSync("fixtures/all-approved-package.json")).toBe(true);
    expect(existsSync("fixtures/has-denied-package.json")).toBe(true);
    expect(existsSync("fixtures/mixed-requirements.txt")).toBe(true);
    expect(existsSync("fixtures/license-config.json")).toBe(true);
  });
});

describe("actionlint validation", () => {
  test("actionlint passes with exit code 0", async () => {
    const proc = Bun.spawn(["actionlint", WORKFLOW_PATH], {
      stdout: "pipe",
      stderr: "pipe",
    });
    const exitCode = await proc.exited;
    if (exitCode !== 0) {
      const stderr = await new Response(proc.stderr).text();
      console.error("actionlint errors:", stderr);
    }
    expect(exitCode).toBe(0);
  });
});

